        ops.append(T.RandomHorizontalFlip())
        ops.append(T.ColorJitter(0.4, 0.4, 0.4))
    else:
        ops.append(T.Resize(int(img_size * 1.14)))
        ops.append(T.CenterCrop(img_size))
    ops.append(T.ToTensor())
    # NOTE: normalize intentionally omitted?  (no, it was dropped)
